const SKILLS = ['react', 'react native', 'typescript', 'javascript', 'next.js', 'nextjs',
  'graphql', 'node.js', 'redux', 'tailwind', 'css', 'html', 'expo', 'firebase',
  'material ui', 'mui', 'angular', 'vue', 'python', 'java', 'php'];

