function inferModality(text) {
  const t = (text || '').toLowerCase();
  if (/\bremote\b/.test(t))    return 'remote';
  if (/\bhybrid\b/.test(t))    return 'hybrid';
  return 'on-site';
}

function extractSkills(text) {
  const t = (text || '').toLowerCase();
  return SKILLS.filter(s => t.includes(s));
}

