const data = $input.first().json;
const jobs = data.jobs || [];

function inferSeniority(text) {
  const t = (text || '').toLowerCase();
  if (/\b(staff|principal)\b/.test(t))     return 'staff';
  if (/\b(lead|tech lead)\b/.test(t))      return 'lead';
  if (/\b(senior|sr\.?)\b/.test(t))        return 'senior';
  if (/\b(mid|middle|pleno)\b/.test(t))    return 'mid';
  if (/\b(junior|jr\.?|entry)\b/.test(t)) return 'junior';
  return 'unknown';
}

return jobs.map(job => ({
  json: {
    source_slug:     'jobicy',
    original_source: 'jobicy',
    external_id:     'jy_' + String(job.id),
    title:           job.jobTitle || '',
    company:         job.companyName || '',
    description:     (job.jobDescription || '').substring(0, 8000),
    location:        job.jobRegion || 'Worldwide',
    modality:        'remote',
    seniority:       inferSeniority(job.jobTitle || ''),
    required_skills: typeof job.jobSkills === 'string'
                      ? job.jobSkills.split(',').map(s => s.trim()).filter(Boolean)
                      : (Array.isArray(job.jobSkills) ? job.jobSkills : []),
    apply_url:       job.url || '',
    posted_at:       job.pubDate || new Date().toISOString(),
    salary_min:      null,
    salary_max:      null,
    salary_currency: 'USD',
    salary_period:   'yearly',
  }
}));

// 1. Dedup en memoria por external_id
const allJobs = $input.all();
const seen = new Map();
for (const item of allJobs) {
  const id = item.json.external_id;
  if (id && !seen.has(id)) seen.set(id, item);
}
const unique = [...seen.values()];

if (unique.length === 0) return [];
console.log(`Items únicos tras dedup en memoria: ${unique.length}`);

// 2. Una sola query a Supabase para traer los IDs que ya existen
const ids = unique.map(i => String(i.json.external_id));
const idParam = ids.join(',');
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_KEY;

let existingSet = new Set();
try {
  const existing = await $helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/rest/v1/job_posts?select=external_id&external_id=in.(${idParam})&limit=2000`,
