  existingSet = new Set((existing || []).map(e => e.external_id));
  console.log(`IDs ya en DB: ${existingSet.size}`);
} catch (e) {
  console.error('Dedup query falló, procediendo con todos:', e.message);
}

// 3. Devolver solo los nuevos
const newJobs = unique.filter(item => !existingSet.has(item.json.external_id));
console.log(`Vacantes nuevas a insertar: ${newJobs.length}`);
return newJobs;

const newJobs = $input.all();
if (newJobs.length === 0) {
  console.log('No hay vacantes nuevas para insertar');
  return [];
}

const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_KEY;

// Guardar mapa external_id → datos originales para el matching
const originalMap = new Map(newJobs.map(item => [item.json.external_id, item.json]));

const rows = newJobs.map(item => {
  const j = item.json;
  return {
    source_slug:     j.source_slug,
    original_source: j.original_source || j.source_slug,
    external_id:     j.external_id,
    title:           j.title,
    company:         j.company,
    description:     (j.description || '').substring(0, 10000),
    location:        j.location || 'Unknown',
    modality:        j.modality || 'unknown',
    seniority:       j.seniority || 'unknown',
    required_skills: Array.isArray(j.required_skills) ? j.required_skills : [],
    apply_url:       j.apply_url,
    posted_at:       j.posted_at,
    salary_min:      j.salary_min || null,
    salary_max:      j.salary_max || null,
    salary_currency: j.salary_currency || 'USD',
    salary_period:   j.salary_period || 'yearly',
  };
});

let inserted = [];
try {
  inserted = await $helpers.httpRequest({
    method: 'POST',
    url: `${supabaseUrl}/rest/v1/job_posts`,
    headers: {
      apikey: supabaseKey,
      Authorization: `Bearer ${supabaseKey}`,
      'Content-Type': 'application/json',
      Prefer: 'return=representation,resolution=ignore-duplicates',
    },
    body: rows,
  });
  console.log(`Insertados: ${Array.isArray(inserted) ? inserted.length : 0}`);
} catch (e) {
  console.error('Batch insert error:', e.message);
  return [];
}

// Combinar datos de Supabase (id, created_at) con datos originales (description, skills) para el matching
return (Array.isArray(inserted) ? inserted : []).map(dbRow => ({
  json: {
    ...originalMap.get(dbRow.external_id),
    id:         dbRow.id,
    created_at: dbRow.created_at,
  }
}));

const PROFILE = $('Config — Profile').first().json;
const job     = $input.first().json;

// ─── Helpers ─────────────────────────────────────────────────────────────────

function normalize(s) { return (s || '').toLowerCase().trim().replace(/[^a-z0-9 .]/g, ''); }

function skillMatch(a, b) {
  const na = normalize(a), nb = normalize(b);
  return na === nb || na.includes(nb) || nb.includes(na);
}

const LEVELS = { junior: 1, mid: 2, senior: 3, lead: 4, staff: 5, unknown: 0 };

// ─── Título (0-20) ────────────────────────────────────────────────────────────
function scoreTitle(title, roles) {
  const t = title.toLowerCase();
  for (const r of roles) {
    const rl = r.toLowerCase();
    if (t === rl || t.includes(rl) || rl.includes(t)) return 20;
  }
  const words = new Set(t.split(/\s+/));
  const best = roles.reduce((b, r) => {
    const rw = r.toLowerCase().split(/\s+/);
    const overlap = rw.filter(w => words.has(w) && w.length > 2).length;
    return Math.max(b, overlap / rw.length);
  }, 0);
  if (best >= 0.5) return 12;
  if (best > 0)    return 5;
  return 0;
}

// ─── Skills (0-35) ────────────────────────────────────────────────────────────
function scoreSkills(required, primary, secondary) {
  const allProfile = [...primary, ...secondary];
  if (!required || required.length === 0) {
    // Sin skills declarados: intentar extraer de descripción
    const desc = (job.description || '').toLowerCase();
    const detected = primary.filter(p => desc.includes(p.toLowerCase()));
    const ratio = detected.length / primary.length;
    return { score: Math.round(25 * ratio), matched: detected, missing: [] };
  }
  const matched = required.filter(r => allProfile.some(p => skillMatch(r, p)));
  const missing = required.filter(r => !allProfile.some(p => skillMatch(r, p)));
  const ratio   = matched.length / required.length;
  const bonus   = matched.some(m => primary.some(p => skillMatch(m, p))) ? 5 : 0;
  return { score: Math.min(Math.round(30 * ratio) + bonus, 35), matched, missing };
}

// ─── Seniority (0-15) ────────────────────────────────────────────────────────
function scoreSeniority(jobSen, profSen) {
  if (jobSen === 'unknown') return 8;
  const diff = Math.abs((LEVELS[jobSen] || 0) - (LEVELS[profSen] || 0));
  if (diff === 0) return 15;
  if (diff === 1) return 9;
  if (diff === 2) return 3;
  return 0;
}

// ─── Modalidad (0-15) ────────────────────────────────────────────────────────
function scoreModality(jobMod) {
  if (jobMod === 'remote') return 15;
  if (jobMod === 'hybrid') return 8;
  return 0;
}

// ─── Ubicación (0-10) ────────────────────────────────────────────────────────
function scoreLocation(loc, mod) {
  if (mod === 'remote') return 10;
  const l = (loc || '').toLowerCase();
  if (l.includes('argentina')) return 10;
  if (l.includes('latam') || l.includes('latin america')) return 7;
  if (l.includes('worldwide') || l.includes('global')) return 8;
  return 0;
}

// ─── Idioma (0-5) ────────────────────────────────────────────────────────────
function scoreLanguage(desc, languages) {
  const d = (desc || '').toLowerCase();
  if (!/english|inglés/.test(d)) return 5;
  const en = languages.find(l => l.lang.toLowerCase() === 'english');
  if (!en) return 0;
  const lvl = { B2: 3, C1: 4, C2: 5, native: 6, B1: 2, A2: 1, A1: 0 }[en.level] || 0;
  return lvl >= 3 ? 5 : (lvl === 2 ? 3 : 0);
}

// ─── Calcular ────────────────────────────────────────────────────────────────
const titleScore    = scoreTitle(job.title, PROFILE.targetRoles);
const skillsResult  = scoreSkills(job.required_skills, PROFILE.primarySkills, PROFILE.secondarySkills);
const seniorityScore = scoreSeniority(job.seniority, PROFILE.seniority);
const modalityScore = scoreModality(job.modality);
const locationScore = scoreLocation(job.location, job.modality);
const languageScore = scoreLanguage(job.description, PROFILE.languages);

const total = titleScore + skillsResult.score + seniorityScore + modalityScore + locationScore + languageScore;

const reasons = [];
if (titleScore >= 12)          reasons.push('Título coincide con tu perfil');
if (skillsResult.matched.length > 0) reasons.push(`Skills: ${skillsResult.matched.slice(0, 4).join(', ')}`);
if (seniorityScore >= 12)      reasons.push(`Seniority exacto (${job.seniority})`);
if (modalityScore === 15)      reasons.push('Modalidad 100% remota');
if (locationScore >= 7)        reasons.push('Ubicación / región compatible');
if (languageScore === 5)       reasons.push('Inglés B2+ aceptado');

const flags = [];
if (!job.salary_min && !job.salary_max) flags.push('Salario no especificado');
if (job.seniority === 'unknown')        flags.push('Seniority no claro en la oferta');
if (skillsResult.missing.length > 2)   flags.push(`Skills que no tenés: ${skillsResult.missing.slice(0, 3).join(', ')}`);

return [{
  json: {
    ...job,
    match: {
      score:           total,
      breakdown: {
        title:     titleScore,
        skills:    skillsResult.score,
        seniority: seniorityScore,
        modality:  modalityScore,
        location:  locationScore,
        language:  languageScore,
      },
      matched_skills:  skillsResult.matched,
      missing_skills:  skillsResult.missing,
      match_reasons:   reasons,
      flags,
      above_threshold: total >= PROFILE.minScoreThreshold,
      above_alert:     total >= PROFILE.alertScoreThreshold,
    }
  }
}];
